package com.proyecto.musicgofx.modelo.entidades;

import java.util.ArrayList;
import java.util.List;

/**
 * Producto especial tipo paquete "Top Ten": un combo de canciones
 * destacadas que el usuario puede comprar como una unidad. Internamente
 * agrupa los IDs de las canciones que forman parte del paquete.
 *
 * <p>Relacion con {@link Cancion}: aqui usamos agregacion por id en
 * vez de referencia directa a objetos para mantener el paquete
 * desacoplado del catalogo a la hora de serializar a JSON.</p>
 *
 * @author Equipo MusicGO
 */
public class PaqueteTopTen extends Producto {

    private String tematica;          // ej: "Pop 2025", "Rock Clasico"
    private List<String> idsCanciones;

    public PaqueteTopTen(String id, String nombre, double precio,
                         String descripcion, String tematica) {
        super(id, nombre, precio, descripcion);
        this.tematica = tematica;
        this.idsCanciones = new ArrayList<>();
    }

    public String getTematica() {
        return tematica;
    }

    public void setTematica(String tematica) {
        this.tematica = tematica;
    }

    public List<String> getIdsCanciones() {
        return idsCanciones;
    }

    /**
     * Agrega un id de cancion al paquete. Evita duplicados.
     * @param idCancion id de la cancion a incluir
     */
    public void agregarCancion(String idCancion) {
        if (idCancion == null || idCancion.isBlank()) return;
        if (!idsCanciones.contains(idCancion)) {
            idsCanciones.add(idCancion);
        }
    }

    public int cantidadCanciones() {
        return idsCanciones.size();
    }

    @Override
    public String getTipo() {
        return "paquete_top_ten";
    }

    @Override
    public void mostrarDetalle() {
        System.out.println("  > Paquete TOP TEN");
        System.out.println("    Nombre   : " + getNombre());
        System.out.println("    Tematica : " + tematica);
        System.out.println("    Canciones incluidas: " + idsCanciones.size());
        for (String id : idsCanciones) {
            System.out.println("      - " + id);
        }
        System.out.println("    Precio   : $" + getPrecio());
    }

    @Override
    public String toString() {
        return "[TopTen] " + getId() + " - " + getNombre()
                + " (" + tematica + ") " + idsCanciones.size() + " canciones $" + getPrecio();
    }
}

package com.proyecto.musicgofx.modelo.entidades;

import java.time.LocalDateTime;

/**
 * Mensaje interno que viaja entre el usuario y la plataforma.
 *
 * Ejemplos de uso en la fase 1:
 * <ul>
 *   <li>El usuario pide reproducir un contenido (REPRODUCIR).</li>
 *   <li>El usuario solicita comprar un producto (COMPRAR).</li>
 *   <li>La plataforma confirma una accion al usuario (CONFIRMACION).</li>
 *   <li>La plataforma reporta un error (ERROR).</li>
 * </ul>
 *
 * <p>La idea es modelar el requerimiento de "interaccion y mensajeria"
 * sin acoplar las clases al canal concreto por el que se manda el
 * mensaje (esto en fase 2 podria ser email, push, etc.).</p>
 *
 * @author Equipo MusicGO
 */
public class Mensaje {

    /** Tipos posibles de mensaje dentro del sistema. */
    public enum Tipo {
        REPRODUCIR, COMPRAR, CONFIRMACION, ERROR, INFO
    }

    private String emisor;
    private String receptor;
    private Tipo tipo;
    private String contenido;
    private LocalDateTime fecha;

    public Mensaje(String emisor, String receptor, Tipo tipo, String contenido) {
        this.emisor = emisor;
        this.receptor = receptor;
        this.tipo = tipo;
        this.contenido = contenido;
        this.fecha = LocalDateTime.now();
    }

    public String getEmisor() {
        return emisor;
    }

    public String getReceptor() {
        return receptor;
    }

    public Tipo getTipo() {
        return tipo;
    }

    public String getContenido() {
        return contenido;
    }

    public LocalDateTime getFecha() {
        return fecha;
    }

    @Override
    public String toString() {
        return "[" + tipo + "] " + emisor + " -> " + receptor + ": " + contenido;
    }
}

package com.proyecto.musicgofx.modelo.entidades;

/**
 * Acumula las estadisticas de un usuario dentro de la plataforma.
 * Vive en composicion con {@link Usuario}: si se elimina al usuario
 * tambien se va su objeto de estadisticas (no tiene sentido por
 * separado).
 *
 * @author Equipo MusicGO
 */
public class Estadisticas {

    private long tiempoEscuchaSegundos;
    private int cancionesEnBiblioteca;
    private int comprasRealizadas;
    private int reproduccionesTotales;

    public Estadisticas() {
        this.tiempoEscuchaSegundos = 0;
        this.cancionesEnBiblioteca = 0;
        this.comprasRealizadas = 0;
        this.reproduccionesTotales = 0;
    }

    public Estadisticas(long tiempoEscuchaSegundos, int cancionesEnBiblioteca,
                        int comprasRealizadas, int reproduccionesTotales) {
        this.tiempoEscuchaSegundos = tiempoEscuchaSegundos;
        this.cancionesEnBiblioteca = cancionesEnBiblioteca;
        this.comprasRealizadas = comprasRealizadas;
        this.reproduccionesTotales = reproduccionesTotales;
    }

    public long getTiempoEscuchaSegundos() {
        return tiempoEscuchaSegundos;
    }

    public int getCancionesEnBiblioteca() {
        return cancionesEnBiblioteca;
    }

    public int getComprasRealizadas() {
        return comprasRealizadas;
    }

    public int getReproduccionesTotales() {
        return reproduccionesTotales;
    }

    public void sumarTiempoEscucha(int segundos) {
        if (segundos <= 0) return;
        this.tiempoEscuchaSegundos += segundos;
        this.reproduccionesTotales++;
    }

    public void setCancionesEnBiblioteca(int cantidad) {
        if (cantidad < 0) return;
        this.cancionesEnBiblioteca = cantidad;
    }

    public void registrarCompra() {
        this.comprasRealizadas++;
    }

    /**
     * Devuelve el tiempo total de escucha en formato hh:mm:ss.
     * @return tiempo formateado
     */
    public String tiempoFormateado() {
        long h = tiempoEscuchaSegundos / 3600;
        long m = (tiempoEscuchaSegundos % 3600) / 60;
        long s = tiempoEscuchaSegundos % 60;
        return String.format("%02d:%02d:%02d", h, m, s);
    }
}

