package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.excepciones.UsuarioNoEncontradoException;
import com.proyecto.musicgofx.excepciones.UsuarioYaExisteException;
import com.proyecto.musicgofx.modelo.entidades.Usuario;
import com.proyecto.musicgofx.modelo.persistencia.RepositorioDatos;
import com.proyecto.musicgofx.excepciones.GmailInvalidoException;
import com.proyecto.musicgofx.excepciones.RecargaSaldoException;
import com.proyecto.musicgofx.excepciones.EdadValidaException;

import util.Validadores;

import java.util.ArrayList;
import java.util.List;

public class GestorUsuarios {

    private final List<Usuario> usuarios;
    private final RepositorioDatos repositorio;
    private Validadores validarGmail;

    public GestorUsuarios(RepositorioDatos repositorio) {
        this.repositorio = repositorio;
        List<Usuario> cargados = repositorio.cargarUsuarios();
        this.usuarios = (cargados != null) ? cargados : new ArrayList<>();
    }

    public List<Usuario> getUsuarios() {
        return usuarios;
    }

    public Usuario buscarPorIdOAlias(String criterio) {
        if (criterio == null || criterio.isBlank()) return null;
        for (Usuario u : usuarios) {
            if (u.getId().equalsIgnoreCase(criterio) || u.getNombre().equalsIgnoreCase(criterio)) {
                return u;
            }
        }
        return null;
    }

    public void registrar(String alias, String correo, int edad ) throws UsuarioYaExisteException {

        if (buscarPorIdOAlias(alias) != null) {

            throw new UsuarioYaExisteException("El alias " + alias + " ya esta en uso.");

        }

        if(!validarGmail.esGmailValido(correo)){

            throw new GmailInvalidoException("El Gmail ingresado "+ correo + " no se puede utilizar");

        }


        boolean correoexiste = usuarios.stream().anyMatch(usuario ->

                usuario.getCorreo() != null && usuario.getCorreo().equalsIgnoreCase(correo));

        if(correoexiste){

            throw  new UsuarioYaExisteException("El correo "+ correo + " ya se encuentra registrado");

        }
         if (edad <= 0 || edad > 120){
            throw new EdadValidaException("Ingrese una edad Valida.");
        }
        Usuario nuevo = new Usuario(alias, correo, edad);

        usuarios.add(nuevo);

        guardarCambios();

    }

    public void modificar(String aliasActual, String nuevoAlias, String nuevoCorreo) throws UsuarioNoEncontradoException, UsuarioYaExisteException {
        Usuario u = buscarPorIdOAlias(aliasActual);
        if (u == null) {
            throw new UsuarioNoEncontradoException("Usuario no encontrado.");
        }

        if (nuevoAlias != null && !nuevoAlias.isBlank() && !nuevoAlias.equalsIgnoreCase(aliasActual)) {
            if (buscarPorIdOAlias(nuevoAlias) != null) {
                throw new UsuarioYaExisteException("El nuevo alias ya esta en uso.");
            }
            u.setNombre(nuevoAlias);
        }

        if (nuevoCorreo != null && !nuevoCorreo.isBlank() && !nuevoCorreo.equalsIgnoreCase(u.getCorreo())) {
            u.setCorreo(nuevoCorreo);
        }

        guardarCambios();
    }

    public void eliminar(String alias) throws UsuarioNoEncontradoException {
        Usuario u = buscarPorIdOAlias(alias);
        if (u == null) {
            throw new UsuarioNoEncontradoException("Usuario no encontrado.");
        }
        usuarios.remove(u);
        guardarCambios();
    }

    /**
     * Cambia el estado del control parental del usuario y guarda los cambios en disco.
     * * @param usuarioActivo El usuario que ha iniciado sesiГіn.
     * @param activar true para encender el control parental, false para apagarlo.
     */
    public void configurarControlParental(Usuario usuarioActivo, boolean activar) {
        if (usuarioActivo != null) {
            usuarioActivo.setControlParental(activar);
            guardarCambios();;
        }
    }
    public void gestionarRecargaSaldo(Usuario usuarioActivo , double recarga){
        if(recarga<=0){
            throw  new RecargaSaldoException("Saldo invalido. Debe ser mayor a 0 ");
        }
        usuarioActivo.recargarSaldo( recarga);
        guardarCambios();
    }

    public void guardarCambios() {
        repositorio.guardarUsuarios(this.usuarios);
    }

}

package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.modelo.entidades.Audio;
import com.proyecto.musicgofx.modelo.entidades.Producto;
import com.proyecto.musicgofx.modelo.persistencia.RepositorioDatos;
import java.util.ArrayList;
import java.util.List;

/**
 * Administra el inventario completo de la aplicacion, incluyendo
 * audios del catalogo y productos disponibles para la venta.
 *
 * @author Equipo MusicGO
 */
public class GestorCatalogo {

    private final RepositorioDatos repositorio;
    private List<Audio> catalogoCompleto;
    private List<Producto> productos;

    /**
     * Inicializa el gestor y las listas de almacenamiento en memoria.
     */
    public GestorCatalogo() {
        this.repositorio = new RepositorioDatos();
        this.catalogoCompleto = new ArrayList<>();
        this.productos = new ArrayList<>();
    }

    /**
     * Carga todos los datos desde los archivos JSON (catalogo, canciones y productos)
     * y los centraliza en las listas del gestor.
     *
     * @return La cantidad total de elementos de audio cargados.
     */
    public int cargarDesdeJson() {
        // Carga de audios desde catalogo.json y canciones.json
        List<Audio> deCatalogo = repositorio.cargarCatalogo();
        List<Audio> deCanciones = repositorio.cargarAudios();

        this.catalogoCompleto.clear();
        this.catalogoCompleto.addAll(deCatalogo);
        this.catalogoCompleto.addAll(deCanciones);

        // Carga de productos desde productos.json
        this.productos = repositorio.cargarProductos();

        return this.catalogoCompleto.size();
    }

    /**
     * Obtiene la lista de todos los audios disponibles.
     *
     * @return Lista de objetos Audio.
     */
    public List<Audio> getTodosLosAudios() {
        return catalogoCompleto;
    }

    /**
     * Obtiene la lista de todos los productos disponibles en la tienda.
     *
     * @return Lista de objetos Producto.
     */
    public List<Producto> getTodosLosProductos() {
        return productos;
    }

    /**
     * Busca un audio especifico mediante su identificador unico.
     *
     * @param id Identificador del audio.
     * @return El audio encontrado o null.
     */
    public Audio buscarAudioPorId(String id) {
        for (Audio audio : catalogoCompleto) {
            if (audio.getId().equalsIgnoreCase(id)) {
                return audio;
            }
        }
        return null;
    }

    /**
     * Busca un producto especifico mediante su identificador unico.
     *
     * @param id Identificador del producto.
     * @return El producto encontrado o null.
     */

    /**
     * Busca un producto en la lista cargada comparando por ID o por nombre.
     * * @param criterio El ID o nombre buscado.
     * @return El producto encontrado o null si no existe.
     */
    public Producto buscarProductoPorIdONombre(String criterio) {
        for (Producto p : getTodosLosProductos()) {
            if (p.getId().equalsIgnoreCase(criterio) || p.getNombre().equalsIgnoreCase(criterio)) {
                return p;
            }
        }
        return null;
    }
}

package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.modelo.entidades.Estadisticas;
import com.proyecto.musicgofx.modelo.entidades.Usuario;

/**
 * Servicio dedicado a mostrar/exportar estadisticas de un usuario.
 *
 * <p>Las estadisticas las acumula el modelo a medida que pasan los
 * eventos (reproducir, comprar, etc.); este gestor solo se encarga
 * de presentarlas bonito y dejar el codigo de la UI mas limpio.</p>
 *
 * @author Equipo MusicGO
 */
public class GestorEstadisticas {

    private final GestorUsuarios gestorUsuarios;

    public GestorEstadisticas(GestorUsuarios gestorUsuarios) {
        this.gestorUsuarios = gestorUsuarios;
    }

    /**
     * Muestra por consola un reporte visual detallado del perfil del usuario.
     * @param idUsuarioOAlias ID o alias del usuario a consultar.
     */
    public void mostrarReporteCompleto(String idUsuarioOAlias) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);

        if (usuario == null) {
            System.err.println("Error: No se pueden generar estadisticas. Usuario no encontrado.");
            return;
        }

        Estadisticas stats = usuario.getEstadisticas();

        System.out.println("\n===========================================");
        System.out.println("   REPORTE DE ACTIVIDAD: " + usuario.getNombre().toUpperCase());
        System.out.println("===========================================");
        System.out.println(" > Tiempo total escuchado:  " + stats.tiempoFormateado());
        System.out.println(" > Reproducciones totales:  " + stats.getReproduccionesTotales());
        System.out.println(" > Canciones en biblioteca: " + stats.getCancionesEnBiblioteca());
        System.out.println(" > Compras realizadas:      " + stats.getComprasRealizadas());
        System.out.println("-------------------------------------------");

        if (stats.getReproduccionesTotales() > 100) {
            System.out.println(" ВЎEres un oyente nivel Leyenda! ");
        } else if (stats.getReproduccionesTotales() > 0) {
            System.out.println(" ВЎSigue descubriendo nueva musica! ");
        } else {
            System.out.println(" Tu historial esta vacio. ВЎEmpieza a escuchar ahora! ");
        }
        System.out.println("===========================================\n");
    }

    /**
     * Simula la exportacion de estadisticas a un formato de texto plano.
     * (En una fase futura, esto podria escribir en un archivo .txt o .csv)
     */
    public void exportarEstadisticas(String idUsuarioOAlias) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario != null) {
            System.out.println("[Sistema] Exportando estadisticas de " + usuario.getNombre() + "...");
            System.out.println("[Exito] Los datos se han enviado al buffer de impresion.");
        } else {
            System.err.println("Error: Usuario no encontrado para exportar.");
        }
    }
}

package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.modelo.entidades.Audio;
import com.proyecto.musicgofx.modelo.entidades.PaqueteTopTen;
import com.proyecto.musicgofx.modelo.entidades.Playlist;
import com.proyecto.musicgofx.modelo.entidades.*;
import com.proyecto.musicgofx.modelo.persistencia.RepositorioDatos;
import com.proyecto.musicgofx.excepciones.SaldoInsuficienteException;
import com.proyecto.musicgofx.excepciones.PagoRechazadoException;

import java.time.LocalDateTime;
import java.util.List;

/**
 * Coordina la adquisicion de productos por parte de los usuarios, gestionando
 * la transaccion, el historial del usuario y la persistencia de los datos.
 *
 * @author Equipo MusicGO
 */
public class GestorCompras {

    private final GestorCatalogo gestorCatalogo;
    private final GestorUsuarios gestorUsuarios;
    private final RepositorioDatos repositorio;

    public enum MetodoPago {
        TARJETACRED, TRANSFERENCIA, BILLETERAAPP
    }

    public GestorCompras(GestorCatalogo catalogo, GestorUsuarios usuarios, RepositorioDatos repositorio) {
        this.gestorCatalogo = catalogo;
        this.gestorUsuarios = usuarios;
        this.repositorio = repositorio;
    }

    /**
     * Procesa la compra delegando el pago al metodo correspondiente.
     */
    public void comprarProducto(String idUsuarioOAlias, String idProductoONombre, MetodoPago metodoPago, String datosPago) throws SaldoInsuficienteException, PagoRechazadoException {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario == null) {
            System.err.println("Error: El usuario '" + idUsuarioOAlias + "' no existe.");
            return;
        }

        Producto producto = gestorCatalogo.buscarProductoPorIdONombre(idProductoONombre);
        if (producto == null) {
            System.err.println("Error: El producto '" + idProductoONombre + "' no existe.");
            return;
        }

        switch (metodoPago) {
            case BILLETERAAPP:
                procesarPagoBilletera(usuario, producto);
                break;
            case TRANSFERENCIA:
                procesarPagoTransferencia(datosPago);
                break;
            case TARJETACRED:
                procesarPagoTarjeta(datosPago);
                break;
        }

        Compra nuevaCompra = new Compra(producto.getId(), usuario.getNombre(), producto.getPrecio(), LocalDateTime.now());
        usuario.registrarCompra(nuevaCompra);

        if (producto instanceof PaqueteTopTen) {
            PaqueteTopTen paquete = (PaqueteTopTen) producto;
            Playlist nuevaPlaylist = new Playlist(paquete.getNombre(), usuario.getNombre());

            for (String idCancion : paquete.getIdsCanciones()) {
                Audio audio = gestorCatalogo.buscarAudioPorId(idCancion);
                if (audio != null) {
                    nuevaPlaylist.agregarAudio(audio);
                }
            }
            usuario.getBiblioteca().getPlaylists().add(nuevaPlaylist);
            System.out.println(" > [Sistema] Se ha creado tu nueva playlist: '" + paquete.getNombre() + "' con " + nuevaPlaylist.getContenido().size() + " canciones.");
        }

        System.out.println("\n--- COMPRA EXITOSA ---");
        System.out.println("Has comprado: " + producto.getNombre());
        System.out.println("Metodo utilizado: " + metodoPago.name());
        System.out.println("----------------------\n");

        gestorUsuarios.guardarCambios();
    }

    private void procesarPagoBilletera(Usuario usuario, Producto producto) throws SaldoInsuficienteException {
        if (usuario.getSaldo() < producto.getPrecio()) {
            throw new SaldoInsuficienteException("Saldo insuficiente en la billetera virtual para comprar " + producto.getNombre() + ". Tienes: $" + usuario.getSaldo() + ", Cuesta: $" + producto.getPrecio());
        }
        usuario.descontarSaldo(producto.getPrecio());
        System.out.println(" > Pago procesado con Billetera App. Nuevo saldo: $" + usuario.getSaldo());
    }

    private void procesarPagoTransferencia(String referencia) throws PagoRechazadoException {
        System.out.println(" > [Aviso] Para transferencias o Pago Movil, utilice los siguientes datos de la empresa:");
        System.out.println("   - Banco: Mercantil (0105)");
        System.out.println("   - RIF: J-41234567-8");
        System.out.println("   - Telefono: 0414-9876543");
        System.out.println(" > [Aviso] Para transferencias, deposite a la cuenta bancaria: 0102-XXXX-XXXX-XXXX");

        if (referencia == null || referencia.isBlank()) {
            throw new PagoRechazadoException("Error: Debe proporcionar un numero de referencia valido para validar la transferencia.");
        }

        System.out.println(" > Verificando transferencia con referencia NВ° " + referencia + "... ВЎAprobada!");
    }

    private void procesarPagoTarjeta(String numeroTarjeta) throws PagoRechazadoException {
        if (numeroTarjeta == null || numeroTarjeta.length() < 16) {
            throw new PagoRechazadoException("Error: Numero de tarjeta de credito invalido. Debe contener al menos 16 digitos.");
        }

        String ultimosDigitos = numeroTarjeta.substring(numeroTarjeta.length() - 4);
        System.out.println(" > Conectando con la pasarela de pago para la tarjeta terminada en " + ultimosDigitos + "... ВЎPago Aprobado!");
    }


    public List<Producto> getProductosDisponibles() {
        return gestorCatalogo.getTodosLosProductos();
    }
}

package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.modelo.entidades.Audio;
import com.proyecto.musicgofx.modelo.entidades.Playlist;
import com.proyecto.musicgofx.modelo.entidades.Usuario;
import com.proyecto.musicgofx.modelo.entidades.Mensaje;
import com.proyecto.musicgofx.excepciones.ContenidoNoEncontradoException;
import com.proyecto.musicgofx.excepciones.ContenidoRestringidoException;

/**
 * Coordina la reproduccion de contenidos y la actualizacion
 * automatica de las estadisticas de escucha del usuario.
 *
 * @author Equipo MusicGO
 */
public class GestorReproduccion {

    private final GestorUsuarios gestorUsuarios;
    private final GestorCatalogo gestorCatalogo;

    /**
     * Inicializa el gestor de reproduccion con los servicios de usuarios y catalogo.
     *
     * @param gestorUsuarios Servicio de gestion de usuarios.
     * @param gestorCatalogo Servicio de gestion del catalogo global.
     */
    public GestorReproduccion(GestorUsuarios gestorUsuarios, GestorCatalogo gestorCatalogo) {
        this.gestorUsuarios = gestorUsuarios;
        this.gestorCatalogo = gestorCatalogo;
    }

    /**
     * Reproduce un audio individual del catalogo y actualiza las estadisticas del usuario.
     *
     * @param idUsuarioOAlias Identificador o alias del usuario.
     * @param idAudioOTitulo Identificador o titulo del audio a reproducir.
     */
    public void reproducirAudio(String idUsuarioOAlias, String idAudioOTitulo) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario == null) {
            System.err.println("Error: No se encontro el usuario para iniciar reproduccion.");
            return;
        }

        Audio audioEncontrado = null;
        for (Audio a : gestorCatalogo.getTodosLosAudios()) {
            if (a.getId().equalsIgnoreCase(idAudioOTitulo) || a.getTitulo().equalsIgnoreCase(idAudioOTitulo)) {
                audioEncontrado = a;
                break;
            }
        }

        if (audioEncontrado == null) {
            System.err.println("Error: El contenido '" + idAudioOTitulo + "' no existe en el catalogo.");
            return;
        }

        audioEncontrado.reproducir();
        usuario.getEstadisticas().sumarTiempoEscucha(audioEncontrado.getDuracionSegundos());
        gestorUsuarios.guardarCambios();

        System.out.println("[Sistema] Estadisticas de '" + usuario.getNombre() + "' actualizadas.");
    }

    /**
     * Reproduce una playlist completa del usuario procesando cada audio individualmente.
     *
     * @param idUsuarioOAlias Identificador o alias del usuario.
     * @param idPlaylist Identificador de la playlist a reproducir.
     */
    public void reproducirPlaylist(String idUsuarioOAlias, String idPlaylist) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario == null) {
            System.err.println("Error: Usuario no encontrado.");
            return;
        }

        Playlist playlist = usuario.getBiblioteca().buscarPorId(idPlaylist);
        if (playlist == null) {
            System.err.println("Error: La playlist no existe en tu biblioteca.");
            return;
        }

        if (playlist.getContenido().isEmpty()) {
            System.out.println("La playlist '" + playlist.getNombre() + "' esta vacia.");
            return;
        }

        System.out.println("\n>>> Iniciando Playlist: " + playlist.getNombre() + " <<<");

        for (Audio a : playlist.getContenido()) {
            a.reproducir();
            usuario.getEstadisticas().sumarTiempoEscucha(a.getDuracionSegundos());
        }

        gestorUsuarios.guardarCambios();

        System.out.println(">>> Fin de la reproduccion de la lista <<<\n");
    }

    /**
     * Metodo principal utilizado por el menu interactivo.
     * Busca el audio en el catalogo, lo reproduce, actualiza estadisticas y persiste los datos.
     *
     * @param usuario Instancia del usuario que solicita la reproduccion.
     * @param idAudioOTitulo Criterio de busqueda del audio (ID o Titulo).
     * @return Mensaje de exito con el titulo del audio reproducido.
     * @throws ContenidoNoEncontradoException Si el audio no se encuentra en el catalogo general.
     */
    public Mensaje reproducir(Usuario usuario, String idAudioOTitulo) throws ContenidoNoEncontradoException {
        Audio audioEncontrado = null;

        for (Audio a : gestorCatalogo.getTodosLosAudios()) {
            if (a.getId().equalsIgnoreCase(idAudioOTitulo) || a.getTitulo().equalsIgnoreCase(idAudioOTitulo)) {
                audioEncontrado = a;
                break;
            }
        }

        if (audioEncontrado == null) {
            throw new ContenidoNoEncontradoException("El contenido '" + idAudioOTitulo + "' no existe en el catalogo.");
        }

        if (audioEncontrado.getCategoria() == Audio.Clasificacion.MAYOR) {
            if (usuario.isControlParental() || usuario.getEdad() < 18) {
                throw new ContenidoRestringidoException("Acceso denegado: El contenido '" + audioEncontrado.getTitulo() +
                        "    ' es para mayores de edad y tu cuenta tiene restricciones (Edad: " + usuario.getEdad() + ").");
            }
        }
        audioEncontrado.reproducir();
        usuario.getEstadisticas().sumarTiempoEscucha(audioEncontrado.getDuracionSegundos());

        gestorUsuarios.guardarCambios();
        return new Mensaje("Sistema", usuario.getNombre(), Mensaje.Tipo.CONFIRMACION, "в–¶ Reproduciendo con exito: " + audioEncontrado.getTitulo());
    }

    public java.util.List<Audio> getTodosLosAudios() {
        return gestorCatalogo.getTodosLosAudios();
    }
}

package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.modelo.entidades.Audio;
import com.proyecto.musicgofx.modelo.entidades.Playlist;
import com.proyecto.musicgofx.modelo.entidades.Usuario;
import com.proyecto.musicgofx.excepciones.UsuarioNoEncontradoException;
import com.proyecto.musicgofx.excepciones.PlaylistNoEncontradaException;
import com.proyecto.musicgofx.excepciones.ErrorCompartirPlaylistException;

/**
 * Administra las listas de reproduccion de los usuarios, gestionando su creacion,
 * modificacion de contenido y sincronizacion con el catalogo global.
 */
public class GestorPlaylists {

    private GestorUsuarios gestorUsuarios;
    private GestorCatalogo gestorCatalogo;

    public GestorPlaylists(GestorUsuarios gestorUsuarios, GestorCatalogo gestorCatalogo) {
        this.gestorUsuarios = gestorUsuarios;
        this.gestorCatalogo = gestorCatalogo;
    }

    /**
     * Crea una nueva playlist para un usuario, genera su ID automaticamente y la guarda en disco.
     */
    public void crearPlaylist(String idUsuarioOAlias, String nombre) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario != null) {
            Playlist nueva = new Playlist(nombre, usuario.getNombre());
            String nuevoId = nueva.getId();
            if (usuario.getBiblioteca().agregarPlaylist(nueva)) {
                System.out.println("Playlist '" + nombre + "' creada con exito. ID: " + nuevoId);
                gestorUsuarios.guardarCambios();
            } else {
                System.err.println("Error: Ya existe una playlist con ese identificador.");
            }
        } else {
            System.err.println("Usuario no encontrado.");
        }
    }

    /**
     * Agrega un audio del catalogo a una playlist especifica del usuario.
     */
    public void agregarAudioAPlaylist(String idUsuarioOAlias, String idPlaylist, String idAudio) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        Audio audio = gestorCatalogo.buscarAudioPorId(idAudio);

        if (usuario != null && audio != null) {
            Playlist playlist = usuario.getBiblioteca().buscarPorId(idPlaylist);
            if (playlist != null) {
                if (playlist.agregarAudio(audio)) {
                    System.out.println("Agregado: " + audio.getTitulo() + " -> " + playlist.getNombre());
                    usuario.refrescarConteoBiblioteca();
                    gestorUsuarios.guardarCambios();
                } else {
                    System.out.println("El audio ya se encuentra en la playlist.");
                }
            } else {
                System.err.println("Playlist no encontrada.");
            }
        } else {
            System.err.println("Usuario o Audio no existen.");
        }
    }

    /**
     * Remueve un audio especifico de una playlist de un usuario y guarda los cambios.
     */
    public void removerAudioDePlaylist(String idUsuarioOAlias, String idPlaylist, String idAudio) throws PlaylistNoEncontradaException {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario == null) {
            System.out.println("Error: Usuario no encontrado.");
            return;
        }

        Playlist playlist = usuario.getBiblioteca().buscarPorId(idPlaylist);
        if (playlist == null) {
            throw new PlaylistNoEncontradaException("Error: No se encontro la playlist con ID '" + idPlaylist + "'.");
        }

        boolean eliminado = playlist.getContenido().removeIf(audio -> audio.getId().equals(idAudio));

        if (eliminado) {
            System.out.println("ВЎAudio removido exitosamente de '" + playlist.getNombre() + "'!");
            usuario.refrescarConteoBiblioteca();
            gestorUsuarios.guardarCambios();
        } else {
            System.out.println("Aviso: Ese audio no se encontraba en la playlist.");
        }
    }

    /**
     * Elimina una playlist completa de la biblioteca.
     */
    public void eliminarPlaylist(String idUsuarioOAlias, String idPlaylist) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario != null) {
            if (usuario.getBiblioteca().eliminarPlaylist(idPlaylist)) {
                System.out.println("Playlist eliminada.");
                usuario.refrescarConteoBiblioteca();
                gestorUsuarios.guardarCambios();
            } else {
                System.err.println("No se pudo eliminar la playlist.");
            }
        } else {
            System.err.println("Usuario no encontrado.");
        }
    }

    /**
     * Muestra el contenido detallado de una playlist especifica por consola.
     */
    public void mostrarContenidoPlaylist(String idUsuarioOAlias, String idPlaylist) {
        Usuario usuario = gestorUsuarios.buscarPorIdOAlias(idUsuarioOAlias);
        if (usuario != null) {
            Playlist p = usuario.getBiblioteca().buscarPorId(idPlaylist);
            if (p != null) {
                System.out.println("\n--- Playlist: " + p.getNombre() + " ---");
                if (p.getContenido().isEmpty()) {
                    System.out.println(" (La playlist esta vacia)");
                } else {
                    for (Audio a : p.getContenido()) {
                        System.out.println(" > " + a.toString());
                    }
                }
            } else {
                System.err.println("Playlist no encontrada.");
            }
        } else {
            System.err.println("Usuario no encontrado.");
        }

    }
    public java.util.List<Audio> getTodosLosAudios() {
        return gestorCatalogo.getTodosLosAudios();
    }

    /**
     * Realiza una copia exacta de una playlist existente en la biblioteca del usuario activo
     * y la transfiere a la biblioteca del usuario destinatario. Bloquea la accion si la
     * playlist es un producto premium (Top Ten).
     *
     * @param usuarioActivo El usuario dueГұo de la playlist original.
     * @param aliasDestinatario El alias del usuario que recibira la copia.
     * @param idPlaylist El ID de la playlist a compartir.
     * @throws UsuarioNoEncontradoException Si el destinatario no existe en el sistema.
     * @throws PlaylistNoEncontradaException Si la playlist no existe en la biblioteca original.
     * @throws ErrorCompartirPlaylistException Si la playlist original es un producto de pago (restringido).
     */
    public void compartirPlaylist(Usuario usuarioActivo, String aliasDestinatario, String idPlaylist) throws UsuarioNoEncontradoException, PlaylistNoEncontradaException, ErrorCompartirPlaylistException {
        Usuario usuariodestinatario = gestorUsuarios.buscarPorIdOAlias(aliasDestinatario);
        if (usuariodestinatario == null) {
            throw new UsuarioNoEncontradoException("Usuario no encontrado.");
        }

        Playlist playlist = usuarioActivo.getBiblioteca().buscarPorId(idPlaylist);
        if (playlist == null) {
            throw new PlaylistNoEncontradaException("Error: No se encontro la playlist con ID '" + idPlaylist + "'.");
        }

        String playlistid = playlist.getId();
        if (playlistid.toUpperCase().startsWith("PRD")) {
            throw new ErrorCompartirPlaylistException("ERROR: La playlist que intentas compartir es un producto paquete top ten");
        }

        Playlist copiaPlaylist = new Playlist(playlist.getNombre() + " Compartida ", usuariodestinatario.getNombre());

        for (Audio audio : playlist.getContenido()) {
            copiaPlaylist.agregarAudio(audio);
        }

        usuariodestinatario.getBiblioteca().agregarPlaylist(copiaPlaylist);
        gestorUsuarios.guardarCambios();
    }
}

package com.proyecto.musicgofx.modelo.servicios;

import com.proyecto.musicgofx.modelo.entidades.*;
import com.proyecto.musicgofx.modelo.persistencia.RepositorioDatos;

/**
 * Gestor encargado de centralizar todas las operaciones exclusivas del
 * perfil de Administrador, tales como el mantenimiento del catГЎlogo de audios,
 * de productos de la tienda y la modificaciГіn de roles de usuarios.
 * * @author Equipo MusicGO
 */
public class GestorAdministrador {

    private final GestorCatalogo gestorCatalogo;
    private final GestorUsuarios gestorUsuarios;
    private final RepositorioDatos repositorio;

    /**
     * Constructor del GestorAdministrador.
     * Recibe e integra las dependencias de los otros gestores y el repositorio global.
     *
     * @param gestorCatalogo Instancia compartida del catГЎlogo global.
     * @param gestorUsuarios Instancia compartida del gestor de usuarios.
     * @param repositorio    Instancia del repositorio Гәnico de persistencia.
     */
    public GestorAdministrador(GestorCatalogo gestorCatalogo, GestorUsuarios gestorUsuarios, RepositorioDatos repositorio) {
        this.gestorCatalogo = gestorCatalogo;
        this.gestorUsuarios = gestorUsuarios;
        this.repositorio = repositorio;
    }

    /**
     * MГ©todo auxiliar privado para validar la seguridad del sistema.
     * Centraliza la verificaciГіn de rol para evitar duplicar cГіdigo en cada funciГіn.
     *
     * @param u Usuario que intenta realizar la operaciГіn.
     * @throws SecurityException Si el usuario no tiene permisos vГЎlidos.
     */
    private void validarAdministrador(Usuario u) {
        if (u == null || u.getRolUsuario() != Usuario.RolUsuario.ADMINISTRADOR) {
            throw new SecurityException("Acceso denegado: Se requieren permisos de ADMINISTRADOR.");
        }
    }



    /**
     * AГұade un nuevo audio (CanciГіn o Podcast) al catГЎlogo general y lo persiste.
     */
    public void agregarAudio(Usuario usuarioActual, Audio nuevoAudio) {
        validarAdministrador(usuarioActual);

        if (nuevoAudio == null) {
            System.err.println("Error: El audio a agregar no puede ser nulo.");
            return;
        }
        gestorCatalogo.getTodosLosAudios().add(nuevoAudio);
        if (nuevoAudio instanceof Cancion) {
            System.out.println(" > [Гүxito] Nueva CANCIГ“N agregada: " + nuevoAudio.getTitulo() + " (ID: " + nuevoAudio.getId() + ")");
        } else if (nuevoAudio instanceof EpisodioPodcast) {
            System.out.println(" > [Гүxito] Nuevo PODCAST agregado: " + nuevoAudio.getTitulo() + " (ID: " + nuevoAudio.getId() + ")");
        }

        repositorio.guardarUsuarios(gestorUsuarios.getUsuarios());
    }

    /**
     * Elimina un audio del catГЎlogo global usando su ID Гәnico.
     */
    public void quitarAudio(Usuario usuarioActual, String idAudio) {
        validarAdministrador(usuarioActual);
        boolean removido = gestorCatalogo.getTodosLosAudios().removeIf(audio -> audio.getId().equalsIgnoreCase(idAudio));

        if (removido) {
            System.out.println(" > [Гүxito] El audio con ID '" + idAudio + "' fue eliminado del catГЎlogo.");
        } else {
            System.err.println("Error: No se encontrГі ningГәn audio con el ID '" + idAudio + "' en el catГЎlogo.");
        }
    }

    /**
     * Modifica las propiedades esenciales de un audio a travГ©s de su identificador.
     */
    public void modificarAudio(Usuario usuarioActual, String idAudio, String nuevoTitulo) {
        validarAdministrador(usuarioActual);

        Audio audioEncontrado = gestorCatalogo.buscarAudioPorId(idAudio);

        if (audioEncontrado != null) {
            String tituloAnterior = audioEncontrado.getTitulo();
            audioEncontrado.setTitulo(nuevoTitulo);
            System.out.println(" > [Гүxito] Audio modificado. De: '" + tituloAnterior + "' A: '" + nuevoTitulo + "'");
        } else {
            System.err.println("Error: No se localizГі el audio con ID '" + idAudio + "' para modificar.");
        }
    }


    /**
     * Introduce un nuevo producto (ArteVisual o PaqueteTopTen) a la tienda virtual.
     */
    public void agregarProducto(Usuario usuarioActual, Producto nuevoProducto) {
        validarAdministrador(usuarioActual);

        if (nuevoProducto == null) {
            System.err.println("Error: El producto a registrar no puede ser nulo.");
            return;
        }
        gestorCatalogo.getTodosLosProductos().add(nuevoProducto);
        System.out.println(" > [Гүxito] Nuevo producto disponible en la tienda: " + nuevoProducto.getNombre());
    }

    /**
     * Retira un producto de la tienda para que ya no pueda ser adquirido.
     */
    public void quitarProducto(Usuario usuarioActual, String idProducto) {
        validarAdministrador(usuarioActual);
        boolean removido = gestorCatalogo.getTodosLosProductos().removeIf(prod -> prod.getId().equalsIgnoreCase(idProducto));
        if (removido) {
            System.out.println(" > [Гүxito] El producto con ID '" + idProducto + "' fue retirado de la tienda.");
        } else {
            System.err.println("Error: No se encontrГі ningГәn producto con el ID '" + idProducto + "'.");
        }
    }

    /**
     * Modifica el precio de venta de un artГӯculo del catГЎlogo de la tienda.
     */
    public void modificarProducto(Usuario usuarioActual, String idProducto, double nuevoPrecio) {
        validarAdministrador(usuarioActual);
        if (nuevoPrecio < 0) {
            System.err.println("Error: El precio de un producto no puede ser negativo.");
            return;
        }
        Producto productoEncontrado = gestorCatalogo.buscarProductoPorIdONombre(idProducto);
        if (productoEncontrado != null) {
            productoEncontrado.setPrecio(nuevoPrecio);
            System.out.println(" > [Гүxito] El precio del producto '" + productoEncontrado.getNombre() + "' se actualizГі a: $" + nuevoPrecio);
        } else {
            System.err.println("Error: El producto con ID o Nombre '" + idProducto + "' no existe.");
        }
    }



    /**
     * Permite cambiar el nivel de privilegios de un usuario en el sistema.
     * Puede ascender a un usuario normal a ADMINISTRADOR o revocar permisos.
     */
    public void modificarRolUsuario(Usuario usuarioActual, String aliasUsuarioAModificar, Usuario.RolUsuario nuevoRol) {
        validarAdministrador(usuarioActual);
        Usuario usuarioDestino = gestorUsuarios.buscarPorIdOAlias(aliasUsuarioAModificar);
        if (usuarioDestino != null) {
            usuarioDestino.setRolUsuario(nuevoRol);
            System.out.println(" > [Гүxito] Permisos actualizados. El usuario '" + usuarioDestino.getNombre() + "' ahora tiene el rol: " + nuevoRol.name());
            gestorUsuarios.guardarCambios();
        } else {
            System.err.println("Error: No se encontrГі ningГәn usuario con el alias '" + aliasUsuarioAModificar + "'.");
        }
    }
}

package com.proyecto.musicgofx.modelo.persistencia;

import com.proyecto.musicgofx.modelo.entidades.*;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

/**
 * Esta clase actГәa como el puente entre la lГіgica de la aplicaciГіn y el almacenamiento en disco.
 * Se encarga de leer y escribir los archivos JSON utilizando el Parser y el Writer.
 */
@SuppressWarnings("SpellCheckingInspection")
public class RepositorioDatos {

    // Rutas de los archivos de datos
    private static final String DIRECTORIO_DATOS = "data/";
    private static final String ARCHIVO_AUDIOS = DIRECTORIO_DATOS + "canciones.json";
    private static final String ARCHIVO_CATALOGO = DIRECTORIO_DATOS + "catalogo.json";
    private static final String ARCHIVO_PRODUCTOS = DIRECTORIO_DATOS + "productos.json";
    private static final String ARCHIVO_USUARIOS = DIRECTORIO_DATOS + "usuarios.json";
    private static final String ARCHIVO_ADMINISTRADORES = DIRECTORIO_DATOS + "administradores.json";


    // Herramientas para convertir de Texto a Objeto (Parser) y de Objeto a Texto (Writer)
    private final JsonParser parser;
    private final JsonWriter writer;

    /**
     * Constructor: Inicializa las herramientas de JSON y asegura que la carpeta 'data' exista.
     */
    public RepositorioDatos() {
        this.parser = new JsonParser();
        this.writer = new JsonWriter();
        crearDirectorioSiNoExiste();
    }

    /**
     * Verifica si existe la carpeta donde se guardan los archivos.
     * Si no existe, la crea automГЎticamente para evitar errores de "Archivo no encontrado".
     */
    private void crearDirectorioSiNoExiste() {
        try {
            Path path = Paths.get(DIRECTORIO_DATOS);
            if (!Files.exists(path)) {
                Files.createDirectories(path);
            }
        } catch (Exception e) {
            System.err.println("Error crГӯtico: No se pudo crear la carpeta de datos: " + e.getMessage());
        }
    }

    /**
     * Lee el archivo 'canciones.json' y lo convierte en una lista de objetos Audio.
     *
     * @return Una lista de canciones cargadas o una lista vacГӯa si el archivo no existe.
     */
    public List<Audio> cargarAudios() {
        Path path = Paths.get(ARCHIVO_AUDIOS);
        if (!Files.exists(path)) {
            return new ArrayList<>();
        }
        try {
            String contenido = Files.readString(path);
            if (contenido.isBlank()) return new ArrayList<>();
            // El parser procesa el texto y nos devuelve objetos Java
            return parser.parsearAudios(contenido);
        } catch (Exception e) {
            System.err.println("Error al leer canciones.json: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Lee el archivo 'catalogo.json' (que contiene tanto canciones como podcasts).
     *
     * @return Lista de audios del catГЎlogo global.
     */
    public List<Audio> cargarCatalogo() {
        Path path = Paths.get(ARCHIVO_CATALOGO);
        if (!Files.exists(path)) {
            System.out.println("[Info] Archivo de catГЎlogo no encontrado, iniciando vacГӯo.");
            return new ArrayList<>();
        }
        try {
            String contenido = Files.readString(path);
            if (contenido.isBlank()) return new ArrayList<>();
            // Usamos parsearAudios porque el catГЎlogo contiene objetos que heredan de Audio
            return parser.parsearAudios(contenido);
        } catch (Exception e) {
            System.err.println("Error al leer catalogo.json: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Lee el archivo 'productos.json' para obtener los items de la tienda (artes, pases VIP, etc).
     *
     * @return Lista de productos disponibles para la compra.
     */
    public List<Producto> cargarProductos() {
        Path path = Paths.get(ARCHIVO_PRODUCTOS);
        if (!Files.exists(path)) return new ArrayList<>();

        try {
            String contenido = Files.readString(path);
            if (contenido.isBlank()) return new ArrayList<>();
            return parser.parsearProductos(contenido);
        } catch (Exception e) {
            System.err.println("Error al cargar productos: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Recupera la base de datos de usuarios, incluyendo sus bibliotecas y estadГӯsticas.
     *
     * @return Lista de usuarios registrados.
     */
    public List<Usuario> cargarUsuarios() {
        Path path = Paths.get(ARCHIVO_USUARIOS);
        if (!Files.exists(path)) return new ArrayList<>();

        try {
            String contenido = Files.readString(path);
            if (contenido.isBlank()) return new ArrayList<>();
            return parser.parsearUsuarios(contenido);
        } catch (Exception e) {
            System.err.println("Error al cargar usuarios: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    public List<Usuario> cargarAdministradores(){
        Path path = Paths.get(ARCHIVO_ADMINISTRADORES);
        if (!Files.exists(path)) return new ArrayList<>();

        try {
            String contenido = Files.readString(path);
            if (contenido.isBlank()) return new ArrayList<>();
            return parser.parsearUsuarios(contenido);
        } catch (Exception e) {
            System.err.println("Error al cargar usuarios: " + e.getMessage());
            return new ArrayList<>();
        }
    }
    /**
     * Guarda la lista actual de usuarios en el archivo 'usuarios.json'.
     * Este mГ©todo se debe llamar cada vez que un usuario compra algo o crea una playlist.
     *
     * @param usuarios La lista de usuarios con los datos actualizados que queremos salvar.
     */
    public void guardarUsuarios(List<Usuario> usuarios) {
        Path path = Paths.get(ARCHIVO_USUARIOS);
        try {
            String json = writer.crearJsonUsuarios(usuarios);
            Files.writeString(path, json);
        } catch (Exception e) {
            System.err.println("Error al intentar guardar los usuarios: " + e.getMessage());
        }
    }

    /**
     * Guarda la lista actual de usuarios con el rol administrador en el archivo 'administradores.json'.
     *  La lista de usuarios con los datos actualizados que queremos salvar.
     */
    public void guardarAdmin(List<Usuario> administradores) {
        Path path = Paths.get(ARCHIVO_ADMINISTRADORES);
        try {
            String json = writer.crearJsonUsuarios(administradores);
            Files.writeString(path, json);
        } catch (Exception e) {
            System.err.println("Error al intentar guardar los usuarios: " + e.getMessage());
        }
    }
}

package com.proyecto.musicgofx.modelo.persistencia;

import com.proyecto.musicgofx.modelo.entidades.*;
import java.time.LocalDateTime;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

/**
 * Clase encargada de analizar (parsear) cadenas de texto en formato JSON
 * y convertirlas en objetos del modelo del sistema de forma manual.
 */
public class JsonParser {

    /**
     * Lee un archivo desde una ruta especifica y devuelve su contenido como cadena de texto.
     */
    public String leerArchivo(String ruta) {
        try {
            return new String(Files.readAllBytes(Paths.get(ruta)));
        } catch (Exception e) {
            return "[]";
        }
    }

    /**
     * Convierte una cadena JSON en una lista de objetos Audio (Cancion o EpisodioPodcast).
     */
    public List<Audio> parsearAudios(String jsonArray) {
        List<Audio> lista = new ArrayList<>();
        List<String> objetos = separarObjetosDeArreglo(jsonArray);

        for (String obj : objetos) {
            String tipo = extraerString(obj, "tipo");
            String categoriastr = extraerString(obj, "categoria");
            Audio.Clasificacion categoria = Audio.Clasificacion.PUBLICO;
            if (categoriastr.equalsIgnoreCase("MAYOR")) {
                categoria = Audio.Clasificacion.MAYOR;
            }
            if (tipo.equalsIgnoreCase("cancion")) {
                lista.add(new Cancion(
                        extraerString(obj, "id"),
                        extraerString(obj, "titulo"),
                        extraerInt(obj, "duracion"),
                        extraerString(obj, "artista"),
                        extraerString(obj, "album"),
                        extraerString(obj, "genero"),
                        categoria

                ));
            } else if (tipo.equalsIgnoreCase("episodio")) {
                lista.add(new EpisodioPodcast(
                        extraerString(obj, "id"),
                        extraerString(obj, "titulo"),
                        extraerInt(obj, "duracion"),
                        extraerString(obj, "anfitrion"),
                        extraerString(obj, "nombrePodcast"),
                        extraerString(obj, "descripcion"),
                        extraerInt(obj, "numeroEpisodio"),
                        categoria
                ));
            }
        }
        return lista;
    }

    /**
     * Convierte una cadena JSON en una lista de objetos Producto (ArteVisualAlbum o PaqueteTopTen).
     */
    public List<Producto> parsearProductos(String jsonArray) {
        List<Producto> lista = new ArrayList<>();
        List<String> objetos = separarObjetosDeArreglo(jsonArray);

        for (String obj : objetos) {
            String tipo = extraerString(obj, "tipo");
            String categorias = extraerString(obj , "categoria");
            Audio.Clasificacion categoria = Audio.Clasificacion.valueOf(categorias.toUpperCase());
            if (tipo.equalsIgnoreCase("arte_visual")) {
                lista.add(new ArteVisualAlbum(
                        extraerString(obj, "id"),
                        extraerString(obj, "nombre"),
                        extraerDouble(obj, "precio"),
                        extraerString(obj, "descripcion"),
                        extraerString(obj, "albumAsociado"),
                        extraerString(obj, "artista"),
                        extraerString(obj, "formato")
                ));
            } else if (tipo.equalsIgnoreCase("paquete_top_ten")) {
                PaqueteTopTen p = new PaqueteTopTen(
                        extraerString(obj, "id"),
                        extraerString(obj, "nombre"),
                        extraerDouble(obj, "precio"),
                        extraerString(obj, "descripcion"),
                        extraerString(obj, "tematica")
                );
                String arregloIds = extraerBloque(obj, "idsCanciones", '[', ']');
                List<String> idsStr = separarCadenasDeArreglo(arregloIds);
                for (String id : idsStr) {
                    p.agregarCancion(id);
                }
                lista.add(p);
            }
        }
        return lista;
    }

    /**
     * Convierte una cadena JSON en una lista de objetos Usuario con todas sus dependencias.
     */
    public List<Usuario> parsearUsuarios(String jsonArray) {
        List<Usuario> lista = new ArrayList<>();
        List<String> objetos = separarObjetosDeArreglo(jsonArray);

        for (String obj : objetos) {
            String id = extraerString(obj, "id");
            String nombre = extraerString(obj, "nombre");
            String correo = extraerString(obj, "correo");
            String rolStr = extraerString(obj, "rol");
            Usuario.RolUsuario rol = Usuario.RolUsuario.NORMAL;
            if (rolStr.equalsIgnoreCase("ADMINISTRADOR")) {
                rol = Usuario.RolUsuario.ADMINISTRADOR;
            }
            double saldo= extraerDouble(obj ,"saldo");
            boolean controParental = extraerBoolean(obj , "controlParental");
            int edad= extraerInt(obj, "edad");




            String st = extraerBloque(obj, "estadisticas", '{', '}');
            Estadisticas estadisticas = new Estadisticas(
                    extraerLong(st, "tiempoEscuchaSegundos"),
                    extraerInt(st, "cancionesEnBiblioteca"),
                    extraerInt(st, "comprasRealizadas"),
                    extraerInt(st, "reproduccionesTotales")
            );

            String arrCompras = extraerBloque(obj, "historialCompras", '[', ']');
            List<Compra> historial = parsearCompras(arrCompras);

            Biblioteca biblioteca = new Biblioteca();
            String biblioObj = extraerBloque(obj, "biblioteca", '{', '}');
            String arrPlaylists = extraerBloque(biblioObj, "playlists", '[', ']');
            List<String> playlistsTxt = separarObjetosDeArreglo(arrPlaylists);

            for (String plTxt : playlistsTxt) {
                String contenidoTxt = extraerBloque(plTxt, "contenido", '[', ']');
                List<Audio> contenido = parsearAudios(contenidoTxt);
                Playlist playlist = new Playlist(
                        extraerString(plTxt, "id"),
                        extraerString(plTxt, "nombre"),
                        extraerString(plTxt, "aliasPropietario"),
                        contenido
                );
                biblioteca.agregarPlaylist(playlist);
            }

            lista.add(new Usuario(id, nombre, correo, biblioteca, estadisticas, historial,  rol , saldo , controParental ,edad));
        }
        return lista;
    }

    /**
     * Convierte una cadena JSON en una lista de objetos Compra.
     */
    public List<Compra> parsearCompras(String jsonArray) {
        List<Compra> lista = new ArrayList<>();
        List<String> objetos = separarObjetosDeArreglo(jsonArray);
        for (String obj : objetos) {
            lista.add(new Compra(
                    extraerString(obj, "idProducto"),
                    extraerString(obj, "aliasUsuario"),
                    extraerDouble(obj, "montoPagado"),
                    LocalDateTime.parse(extraerString(obj, "fecha"))
            ));
        }
        return lista;
    }

    /**
     * Extrae el valor de texto (String) asociado a una clave en el JSON.
     */
    private String extraerString(String json, String clave) {
        String patron = "\"" + clave + "\":\"";
        int idx = json.indexOf(patron);
        if (idx == -1) return "";
        int inicio = idx + patron.length();
        int fin = json.indexOf("\"", inicio);
        return json.substring(inicio, fin);
    }

    /**
     * Extrae el valor numerico entero (int) asociado a una clave en el JSON.
     */
    private int extraerInt(String json, String clave) {
        return (int) Double.parseDouble(extraerNumero(json, clave));
    }

    /**
     * Extrae el valor decimal (double) asociado a una clave en el JSON.
     */
    private double extraerDouble(String json, String clave) {
        return Double.parseDouble(extraerNumero(json, clave));
    }

    /**
     * Extrae el valor numerico largo (long) asociado a una clave en el JSON.
     */
    private long extraerLong(String json, String clave) {
        return (long) Double.parseDouble(extraerNumero(json, clave));
    }

    /**
     * Localiza un numero en formato crudo dentro del JSON.
     */
    private String extraerNumero(String json, String clave) {
        String patron = "\"" + clave + "\":";
        int idx = json.indexOf(patron);
        if (idx == -1) return "0";
        int inicio = idx + patron.length();
        int fin = inicio;
        while (fin < json.length() && (Character.isDigit(json.charAt(fin)) || json.charAt(fin) == '.' || json.charAt(fin) == '-')) {
            fin++;
        }
        String num = json.substring(inicio, fin);
        return num.isEmpty() ? "0" : num;
    }

    /**
     * Extrae un bloque completo de JSON delimitado por caracteres de apertura y cierre.
     */
    private String extraerBloque(String json, String clave, char apertura, char cierre) {
        String patron = "\"" + clave + "\":";
        int idx = json.indexOf(patron);
        if (idx == -1) return "";
        int inicio = json.indexOf(apertura, idx);
        if (inicio == -1) return "";

        int abiertas = 0;
        int fin = -1;
        boolean comillas = false;
        for (int i = inicio; i < json.length(); i++) {
            char c = json.charAt(i);
            if (c == '"') comillas = !comillas;
            if (!comillas) {
                if (c == apertura) abiertas++;
                if (c == cierre) abiertas--;
                if (abiertas == 0) {
                    fin = i + 1;
                    break;
                }
            }
        }
        return fin != -1 ? json.substring(inicio, fin) : "";
    }

    /**
     * Separa un arreglo JSON de objetos en una lista de cadenas individuales.
     */
    private List<String> separarObjetosDeArreglo(String jsonArray) {
        List<String> objetos = new ArrayList<>();
        if (jsonArray == null || jsonArray.isEmpty()) return objetos;
        int llavesAbiertas = 0;
        StringBuilder objActual = new StringBuilder();
        boolean comillas = false;

        for (char c : jsonArray.toCharArray()) {
            if (c == '"') comillas = !comillas;
            if (!comillas) {
                if (c == '{') llavesAbiertas++;
                if (llavesAbiertas > 0) objActual.append(c);
                if (c == '}') {
                    llavesAbiertas--;
                    if (llavesAbiertas == 0) {
                        objetos.add(objActual.toString());
                        objActual = new StringBuilder();
                    }
                }
            } else if (llavesAbiertas > 0) {
                objActual.append(c);
            }
        }
        return objetos;
    }

    /**
     * Separa un arreglo JSON de cadenas en una lista de textos.
     */
    private List<String> separarCadenasDeArreglo(String jsonArray) {
        List<String> cadenas = new ArrayList<>();
        if (jsonArray == null || jsonArray.isEmpty()) return cadenas;
        boolean comillas = false;
        StringBuilder actual = new StringBuilder();
        for (char c : jsonArray.toCharArray()) {
            if (c == '"') {
                if (comillas) cadenas.add(actual.toString());
                actual = new StringBuilder();
                comillas = !comillas;
            } else if (comillas) {
                actual.append(c);
            }
        }
        return cadenas;
    }
    /**
     * Busca una clave en un bloque JSON y extrae su valor booleano.
     * Si no encuentra la clave o hay un error, devuelve false por defecto.
     */
    private boolean extraerBoolean(String json, String clave) {
        String patron = "\"" + clave + "\":";
        int inicio = json.indexOf(patron);

        if (inicio == -1) {
            return false;
        }
        inicio += patron.length();
        int finComa = json.indexOf(",", inicio);
        int finLlave = json.indexOf("}", inicio);

        int fin;
        if (finComa != -1 && finLlave != -1) {
            fin = Math.min(finComa, finLlave);
        } else if (finComa != -1) {
            fin = finComa;
        } else if (finLlave != -1) {
            fin = finLlave;
        } else {
            fin = json.length();
        }

        String valorStr = json.substring(inicio, fin).trim();

        valorStr = valorStr.replace("\"", "");
        return Boolean.parseBoolean(valorStr);
    }
}

package com.proyecto.musicgofx.modelo.persistencia;

import com.proyecto.musicgofx.modelo.entidades.*;
import java.util.List;

public class JsonWriter {

    public String crearJsonAudios(List<Audio> lista) {
        StringBuilder sb = new StringBuilder();
        sb.append("[\n");
        for (int i = 0; i < lista.size(); i++) {
            Audio a = lista.get(i);
            sb.append("  {");
            sb.append("\"id\":\"").append(a.getId()).append("\",");
            sb.append("\"titulo\":\"").append(a.getTitulo()).append("\",");
            sb.append("\"duracionSegundos\":").append(a.getDuracionSegundos()).append(",");
            sb.append("\"tipo\":\"").append(a.getTipo()).append("\",");
            sb.append("\"categoria\":\"").append(a.getCategoria().name()).append("\"");

            if (a instanceof Cancion) {
                Cancion c = (Cancion) a;
                sb.append(",\"artista\":\"").append(c.getArtista()).append("\",");
                sb.append("\"album\":\"").append(c.getAlbum()).append("\",");
                sb.append("\"genero\":\"").append(c.getGenero()).append("\"");
            } else if (a instanceof EpisodioPodcast) {
                EpisodioPodcast ep = (EpisodioPodcast) a;
                sb.append(",\"anfitrion\":\"").append(ep.getAnfitrion()).append("\",");
                sb.append("\"nombrePodcast\":\"").append(ep.getNombrePodcast()).append("\",");
                sb.append("\"descripcion\":\"").append(ep.getDescripcion()).append("\",");
                sb.append("\"numeroEpisodio\":").append(ep.getNumeroEpisodio());
            }
            sb.append("}");
            if (i < lista.size() - 1) sb.append(",\n");
        }
        sb.append("\n]");
        return sb.toString();
    }

    public String crearJsonProductos(List<Producto> lista) {
        StringBuilder sb = new StringBuilder();
        sb.append("[\n");
        for (int i = 0; i < lista.size(); i++) {
            Producto p = lista.get(i);
            sb.append("  {");
            sb.append("\"id\":\"").append(p.getId()).append("\",");
            sb.append("\"nombre\":\"").append(p.getNombre()).append("\",");
            sb.append("\"precio\":").append(p.getPrecio()).append(",");
            sb.append("\"descripcion\":\"").append(p.getDescripcion()).append("\",");
            sb.append("\"tipo\":\"").append(p.getTipo()).append("\"");

            if (p instanceof ArteVisualAlbum) {
                ArteVisualAlbum arte = (ArteVisualAlbum) p;
                sb.append(",\"albumAsociado\":\"").append(arte.getAlbumAsociado()).append("\",");
                sb.append("\"artista\":\"").append(arte.getArtista()).append("\",");
                sb.append("\"formato\":\"").append(arte.getFormato()).append("\"");
            } else if (p instanceof PaqueteTopTen) {
                PaqueteTopTen pq = (PaqueteTopTen) p;
                sb.append(",\"tematica\":\"").append(pq.getTematica()).append("\",");
                sb.append("\"idsCanciones\":[");
                for (int j = 0; j < pq.getIdsCanciones().size(); j++) {
                    sb.append("\"").append(pq.getIdsCanciones().get(j)).append("\"");
                    if (j < pq.getIdsCanciones().size() - 1) sb.append(",");
                }
                sb.append("]");
            }
            sb.append("}");
            if (i < lista.size() - 1) sb.append(",\n");
        }
        sb.append("\n]");
        return sb.toString();
    }

    public String crearJsonUsuarios(List<Usuario> lista) {
        StringBuilder sb = new StringBuilder();
        sb.append("[\n");
        for (int i = 0; i < lista.size(); i++) {
            Usuario u = lista.get(i);
            sb.append("  {");
            sb.append("\"id\":\"").append(u.getId()).append("\",");
            sb.append("\"nombre\":\"").append(u.getNombre()).append("\",");
            sb.append("\"correo\":\"").append(u.getCorreo()).append("\",");
            sb.append("\"saldo\":").append(u.getSaldo()).append(",");
            sb.append("\"rol\":\"").append(u.getRolUsuario().name()).append("\",");
            sb.append("\"controlParental\":\"").append(u.isControlParental()).append("\",");
            sb.append("\"edad\":").append(u.getEdad()).append(",");

            // Estadisticas
            sb.append("\"estadisticas\":{");
            sb.append("\"tiempoEscuchaSegundos\":").append(u.getEstadisticas().getTiempoEscuchaSegundos()).append(",");
            sb.append("\"cancionesEnBiblioteca\":").append(u.getEstadisticas().getCancionesEnBiblioteca()).append(",");
            sb.append("\"comprasRealizadas\":").append(u.getEstadisticas().getComprasRealizadas()).append(",");
            sb.append("\"reproduccionesTotales\":").append(u.getEstadisticas().getReproduccionesTotales());
            sb.append("},");

            // Historial de compras
            sb.append("\"historialCompras\":").append(crearJsonCompras(u.getHistorialCompras())).append(",");

            // Biblioteca y Playlists
            sb.append("\"biblioteca\":{");
            sb.append("\"playlists\":[\n");
            List<Playlist> playlists = u.getBiblioteca().getPlaylists();
            for (int j = 0; j < playlists.size(); j++) {
                Playlist pl = playlists.get(j);
                sb.append("      {");
                sb.append("\"id\":\"").append(pl.getId()).append("\",");
                sb.append("\"nombre\":\"").append(pl.getNombre()).append("\",");
                sb.append("\"aliasPropietario\":\"").append(pl.getAliasPropietario()).append("\",");
                sb.append("\"contenido\":").append(crearJsonAudios(pl.getContenido()));
                sb.append("}");
                if (j < playlists.size() - 1) sb.append(",");
            }
            sb.append("    ]");
            sb.append("}");

            sb.append("}");
            if (i < lista.size() - 1) sb.append(",\n");
        }
        sb.append("\n]");
        return sb.toString();
    }

    public String crearJsonCompras(List<Compra> lista) {
        StringBuilder sb = new StringBuilder();
        sb.append("[");
        for (int i = 0; i < lista.size(); i++) {
            Compra c = lista.get(i);
            sb.append("{");
            sb.append("\"idProducto\":\"").append(c.getIdProducto()).append("\",");
            sb.append("\"aliasUsuario\":\"").append(c.getAliasUsuario()).append("\",");
            sb.append("\"montoPagado\":").append(c.getMontoPagado()).append(",");
            sb.append("\"fecha\":\"").append(c.getFecha().toString()).append("\"");
            sb.append("}");
            if (i < lista.size() - 1) sb.append(",");
        }
        sb.append("]");
        return sb.toString();
    }
}

